import type { CapacitorConfig } from '@capacitor/cli';

/**
 * Capacitor configuration for TuBus Express native app.
 *
 * Strategy: the web bundle generated by `ng build --configuration production`
 * (output `dist/tubus-express/browser`) is wrapped 1:1 in a native WebView.
 * The same bundle that serves https://tubusexpress.com is what runs inside
 * the APK — zero divergence between web and native shells.
 *
 * `androidScheme: 'https'` ensures the WebView exposes a secure context,
 * which is required for Web Crypto, Notifications, and cookies behaving
 * the same as production web. Without this, Android would default to
 * `http://localhost` which breaks subtle browser APIs the SPA relies on.
 *
 * `allowNavigation` whitelists outbound origins the app can navigate to
 * via the WebView. Plain HTTP requests via fetch/XHR are NOT gated by this
 * (CORS handles those); this only restricts top-level navigations.
 */
const config: CapacitorConfig = {
  appId: 'com.tubusexpress.app',
  appName: 'TuBus Express',
  webDir: 'dist/tubus-express/browser',
  server: {
    androidScheme: 'https',
    allowNavigation: [
      'api.tubusexpress.com',
      'res.cloudinary.com',
      '*.googleusercontent.com',
      '*.firebaseio.com',
      '*.googleapis.com',
    ],
  },
  android: {
    // Solid background until web content paints. Matches the brand primary
    // color so the splash-to-content transition feels seamless.
    backgroundColor: '#001D56',
  },
  plugins: {
    SplashScreen: {
      // Show the splash for up to 2 seconds, then auto-hide. The actual
      // hide happens earlier — `SplashScreen.hide()` is invoked by the
      // SplashService once Angular bootstrap completes.
      launchShowDuration: 2000,
      launchAutoHide: true,
      backgroundColor: '#001D56',
      // Letterbox to honour the source aspect ratio; the brand asset is
      // a square logo and we don't want it stretched on tall screens.
      androidScaleType: 'CENTER_CROP',
      showSpinner: false,
      androidSpinnerStyle: 'large',
      spinnerColor: '#FFFFFF',
      splashFullScreen: true,
      splashImmersive: true,
    },
    StatusBar: {
      // Light icons on dark background. Setting via config is necessary
      // because the plugin reads it at native init (before JS runs).
      style: 'DARK',
      backgroundColor: '#001D56',
      overlaysWebView: false,
    },
    FirebaseAuthentication: {
      // skipNativeAuth: false → the plugin uses the native Google Sign-In
      // SDK (vs falling back to the Firebase web SDK in the WebView, which
      // breaks because Google blocks WebView-based OAuth since 2021).
      skipNativeAuth: false,
      // Enabled providers. 'apple.com' is iOS-only at runtime — the plugin
      // throws on Android if invoked, but listing it here is mandatory for
      // the iOS native SDK to register the Sign in with Apple capability.
      // Must also be enabled in Firebase Console → Authentication → Sign-in
      // method → Apple (requires Apple Service ID + key configured).
      providers: ['google.com', 'apple.com'],
    },
  },
};

export default config;
